@@ -1728,11 +1728,0 @@
-static inline void emit_fp_ucom_avx10_2(MacroAssembler* masm, enum FP_PREC pt,
-                                        XMMRegister p, XMMRegister q) {
-  if (pt == fp_prec_hlf) {
-    __ evucomxsh(p, q);
-  } else if (pt == fp_prec_flt) {
-    __ evucomxss(p, q);
-  } else {
-    __ evucomxsd(p, q);
-  }
-}
-
@@ -1750,31 +1739,7 @@
-static inline void emit_fp_nan(MacroAssembler* masm, enum FP_PREC pt,
-                               XMMRegister dst, Register rt) {
-  if (pt == fp_prec_hlf) {
-    __ movl(rt, 0x00007e00); // Float16.NaN
-    __ evmovw(dst, rt);
-  } else if (pt == fp_prec_flt) {
-    __ movl(rt, 0x7fc00000); // Float.NaN
-    __ movdl(dst, rt);
-  } else {
-    __ mov64(rt, 0x7ff8000000000000L); // Double.NaN
-    __ movdq(dst, rt);
-  }
-}
-
-static inline void emit_fp_equal(MacroAssembler* masm, XMMRegister dst,
-                                 XMMRegister a, XMMRegister b,
-                                 bool min) {
-  if (min) {
-    __ vpor(dst, a, b, Assembler::AVX_128bit);
-  } else {
-    __ vpand(dst, a, b, Assembler::AVX_128bit);
-  }
-}
-
